import { NextResponse } from 'next/server'
import type { NextRequest } from 'next/server'

export function middleware(request: NextRequest) {
  const start = performance.now()
  const timestamp = new Date().toISOString()
  const { method, nextUrl: { pathname, search } } = request

  // Log the incoming request
  console.log(
    `[${timestamp}] ${method} ${pathname}${search} → processing...`
  )

  // Get the response and log the outcome
  const response = NextResponse.next()

  response.headers.set('x-request-timestamp', timestamp)

  const duration = (performance.now() - start).toFixed(2)
  console.log(
    `[${timestamp}] ${method} ${pathname}${search} → ${response.status} (${duration}ms)`
  )

  return response
}

// Match all paths except Next.js internals and static files
export const config = {
  matcher: [
    /*
     * Match all request paths except:
     * - _next/static (static files)
     * - _next/image (image optimization files)
     * - favicon.ico (favicon file)
     * - images, manifest, and other static assets
     */
    '/((?!_next/static|_next/image|favicon\\.ico|.*\\.(?:svg|png|jpg|jpeg|gif|webp)$).*)',
  ],
}
